diffs.patch:
Index: bench-targets/feature/src/formatTitle.mjs
===================================================================
--- bench-targets/feature/src/formatTitle.mjs	
+++ bench-targets/feature/src/formatTitle.mjs	
@@ -1,5 +1,15 @@
 export function formatTitle(value, mode = 'plain') {
   if (mode === 'upper') return value.toUpperCase()
   if (mode === 'lower') return value.toLowerCase()
+  if (mode === 'title') return formatTitleTitleCase(value)
   return value
 }
+
+function formatTitleTitleCase(value) {
+  const words = value.split(' ')
+  const mapped = words.map(word => {
+    if (word.length === 0) return word
+    return word[0].toUpperCase() + word.slice(1).toLowerCase()
+  })
+  return mapped.join(' ')
+}

